import random

CONCEPT_TYPE = "number_theory.legendre_symbol"
CONCEPT_GROUP = "number_theory"

def generate(seed):
    rng = random.Random(seed)

    # Generate two distinct primes
    p = rng.choice([3, 5, 7, 11, 13, 17, 19, 23])
    q = rng.choice([2, 3, 5, 7, 11, 13, 17, 19, 23])
    while p == q:
        q = rng.choice([2, 3, 5, 7, 11, 13, 17, 19, 23])

    # Generate a random integer a such that 1 <= a < p
    a = rng.randint(1, p - 1)

    # Generate the problem
    problem = (
        f"Given the prime numbers p = {p} and q = {q}, compute the Legendre symbol (a/p) where a = {a}."
    )

    # Compute the Legendre symbol using the quadratic reciprocity law
    if a == 1:
        answer = 1
    elif a == -1:
        answer = -1 if p % 4 == 3 else 1
    elif a == 2:
        answer = 1 if p % 8 in [1, 7] else -1
    else:
        # For other values of a, we need to use the quadratic reciprocity law
        if q % 4 == 3 and p % 4 == 3:
            answer = -legendre_symbol(q, p)
        else:
            answer = legendre_symbol(q, p)

    return problem, str(answer)

def legendre_symbol(a, p):
    if a % p == 0:
        return 0
    else:
        x = pow(a, (p - 1) // 2, p)
        return 1 if x == 1 else -1

# Example usage
seed = 0
problem, answer = generate(seed)
print(f"Seed: {seed}, Problem: {problem}, Answer: {answer}")
